mapper.select:
/* selectVehicleInformationForApi */ SELECT MV.VOWNKEY , MV.VEHICKY , MV.VHCSNAM , MV.VHCFNAM , MV.DLVTYPE , MV.VHCOPTY , MV.VHCTYPE , MV.VHCTNCD , MV.VHCMAXW , MV.DRVERNM , MV.DRVERPH , MV.VHCMEMO
, WA.WAREKEY
FROM ${common.commonSchema}.MVHCMA MV
INNER JOIN ${common.schema}.WASNHD WA ON WA.VEHICKY = MV.VEHICKY
INNER JOIN ${common.schema}.OOUBHD WA ON WA.VEHICKY = MV.VEHICKY
AND WA.EOASNKY = #{param.eoasnky}
AND WA.OUTBOKY = #{param.outboky}
AND MV.VHCFNAM = #{param.vhcfnam}
AND MV.VHUSEYN = 'Y'

/* selectShpplkyAndVhplnkyForApi */
SELECT
    OBI.SHPPLKY, OBI.VHPLNKY, OBI.PLNSIZE
FROM
    ${common.schema}.OOUBIT OBI
WHERE
    OBI.OUTBOKY = #{param.outboky}
    AND OBI.SKUMKEY = #{param.skumkey}

/* hasStockForApi */ SELECT WS.STOCKKY, WS.WAREKEY , WS.AREAKEY, WS.LOCAKEY , WS.LOLAYER, WS.LOTNMKY, WS.OWNERKY , WS.CUSTCOD, WS.SKUMKEY, WS.SKUDESC , WS.SKUWEIG, WS.SKUWIDT, WS.SKULENG, WS.SKUTHIC , WS.STLOTNB, WS.PURCNUM, WS.ORDERLN , WS.REGIORG, WS.DESTORG, WS.REGIMOD, WS.DESTMOD , WS.ITEMCOD, WS.STOTQTY, WS.SALLQTY, WS.SBLOQTY , WS.SUOMKEY, WS.RCVDCDT, WS.LOTAT01, WS.LOTAT02 , WS.LOTAT03, WS.STKSTAT, WS.EMSKUYN , WS.BLOCKID, WS.RCVDCKY , WS.RCVDCIT, WS.ADJSOKY, WS.ADJSOIT, WS.PHYSOKY , WS.PHYSOIT, WS.SHPDCKY, WS.SHPDCIT, WS.TASKOKY , WS.TASKOIT, WS.CREDATE, WS.CRETIME, WS.CREUSER , WS.LMODATE, WS.LMOTIME, WS.LMOUSER, WS.UPDTCHK FROM ${common.schema}.WSTKKY WS WHERE WS.SKUMKEY = #{param.skumkey}
AND WS.WAREKEY = #{param.warekey}
AND WS.STOCKKY = #{param.stockky}
AND WS.AREAKEY = #{param.areakey}
AND WS.LOCAKEY = #{param.locakey}
AND WS.LOLAYER = #{param.lolayer}
AND WS.AREAKEY = #{param.frareky}
AND WS.LOCAKEY = #{param.frlocky}
AND WS.LOLAYER = #{param.frlayer}
AND WS.LOLAYER = #{param.stlayer}
GROUP BY WS.STOCKKY, WS.WAREKEY , WS.AREAKEY, WS.LOCAKEY , WS.LOLAYER, WS.LOTNMKY, WS.OWNERKY , WS.CUSTCOD, WS.SKUMKEY, WS.SKUDESC , WS.SKUWEIG, WS.SKUWIDT, WS.SKULENG, WS.SKUTHIC , WS.STLOTNB, WS.PURCNUM, WS.ORDERLN , WS.REGIORG, WS.DESTORG, WS.REGIMOD, WS.DESTMOD , WS.ITEMCOD, WS.STOTQTY, WS.SALLQTY, WS.SBLOQTY , WS.SUOMKEY, WS.RCVDCDT, WS.LOTAT01, WS.LOTAT02 , WS.LOTAT03, WS.STKSTAT, WS.EMSKUYN , WS.BLOCKID, WS.RCVDCKY , WS.RCVDCIT, WS.ADJSOKY, WS.ADJSOIT, WS.PHYSOKY , WS.PHYSOIT, WS.SHPDCKY, WS.SHPDCIT, WS.TASKOKY , WS.TASKOIT, WS.CREDATE, WS.CRETIME, WS.CREUSER , WS.LMODATE, WS.LMOTIME, WS.LMOUSER, WS.UPDTCHK

/* selectWtakitListForApiValidation */ SELECT
WTK.TASKOKY, WTK.TASKOIT,
WTK.WAREKEY, WTK.TASKDAT, WTK.DOCCATE, WTK.DOCTYPE, WTK.TASKSTS, WTK.LOTNMKY, OWNRNAM, WTK.OWNERKY, WTK.CUSTCOD, WTK.CUSTNAM, WTK.SKUMKEY, WTK.SKUDESC, WTK.FRAREKY, WTK.FRLOCKY, WTK.FRLAYER, WTK.TOAREKY, WTK.TOLOCKY, WTK.TOLAYER, WTK.EQUIPKY, WTK.FORDQTY, WTK.TCMPQTY, WTK.ALLGRKY, WTK.MVSTDAT, WTK.MVSTTIM, WTK.MVEDDAT, WTK.MVEDTIM, WTK.PARSNCD, WTK.PARSNNM, WTK.PKRSNCD, WTK.PKRSNNM, WTK.STOCKKY, WTK.PLNSIZE, WTK.EOASNKY, WTK.EOASNIT, WTK.COSTRKY, WTK.COSTRIT, WTK.RCVDCKY, WTK.RCVDCIT, WTK.OUTBOKY, WTK.OUTBOIT, WTK.SHPDCKY, WTK.SHPDCIT, WTK.VHPLNKY, WTK.VHPLNIT,
WTK.CREDATE, WTK.CRETIME, WTK.CREUSER, WTK.LMODATE, WTK.LMOTIME, WTK.LMOUSER, WTK.UPDTCHK FROM ${common.schema}.WTAKIT WTK WHERE WTK.WAREKEY = #{param.warekey} AND WTK.SHPDCKY = #{param.shpdcky}
